#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int status = 1;
    int *values = NULL;
    FILE *stream = NULL;
    size_t count;
    if (scanf("%zu", &count) != 1 || count > 20) goto cleanup;
    values = count == 0 ? NULL : malloc(count * sizeof *values);
    if (count != 0 && values == NULL) goto cleanup;
    stream = tmpfile();
    if (stream == NULL) goto cleanup;
    long long sum = 0;
    for (size_t i = 0; i < count; ++i) { if (scanf("%d", &values[i]) != 1) goto cleanup; sum += values[i]; }
    printf("%lld\n", sum);
    status = 0;
cleanup:
    if (stream != NULL) fclose(stream);
    free(values);
    return status;
}
